import collections
from typing import List

def checkValid(matrix: List[List[int]]) -> bool:
  if not matrix or len(matrix) < 1 or len(matrix) > 100:
    return False

  n = len(matrix)
  print(f"n: {n}")
  
  def _is_valid(list_: List[int]):
    #Validate that each row/column does not contain duplicates 
    # and contains all n numbers
    # If any list contains items < n, return False
    if len(list_) < n:
      return False    
    # If duplicates, return False
    duplicates = [item for item in set(list_) if list_.count(item) > 1]
    if (len(duplicates) > 0):
      return False
    # If invalid number in the list, return False
    valid_list = [x for x in range(1,n+1)]
    for item in list_:
      if item not in valid_list:
        return False
    return True
  
  row_len = len(matrix[0])
  col_len = row_len
  # Check if each row is valid
  all_rows = [row for row in matrix]
  row_valid = False
  for one_row in all_rows:
    one_row_valid = _is_valid(one_row)
    if one_row_valid == False:
      return False
    else:
      row_valid = True

  # Check if each column is valid
  all_cols = []
  for i in range(row_len):
    col = []
    for j in range(col_len):
      col.append(matrix[j][i])
    all_cols.append(col)
  
  col_valid = False
  for one_col in all_cols:
    one_col_valid = _is_valid(one_col)
    if one_col_valid == False:
      return False
    else:
      col_valid = True

  if row_valid and col_valid:
    return True
  else:
    return False

